import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [students, setStudents] = useState([]);

  useEffect(() => {
    // Port 3000 waa halka matoorkaagu ka kacay
    axios.get('http://localhost:3000/students')
      .then(res => {
        setStudents(res.data);
        console.log("Xogta ardayda waa la helay!");
      })
      .catch(err => {
        console.error("Cillad ayaa jirta:", err);
      });
  }, []);

  return (
    <div style={{ padding: '20px', textAlign: 'center' }}>
      <h1>Xaadiriska Ardayda Dugsiga</h1>
      <table border="1" width="100%" style={{ borderCollapse: 'collapse', marginTop: '20px' }}>
        <thead style={{ background: '#2c3e50', color: 'white' }}>
          <tr>
            <th>Magaca Ardayga</th>
            <th>Fasalka</th>
            <th>Xaadiris</th>
          </tr>
        </thead>
        <tbody>
          {students.map(s => (
            <tr key={s._id}>
              <td>{s.magaca}</td>
              <td>{s.fasalka}</td>
              <td>
                <button style={{ background: 'green', color: 'white' }}>√ Sax</button>
                <button style={{ background: 'red', color: 'white', marginLeft: '5px' }}>X Maqan</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default App;
